	static let maxTerm = 218
	static let repeatNodeCount = 23

	static let nodePropNames: [String] = ["isolate", "group", "openedBy", "closedBy"]

	static func buildNodeProps(_ extraProps: [String: NodePropBase] = [:]) -> [[Any]]? {
		let allProps = nodePropByName.merging(extraProps) { $1 }
		var result: [[Any]] = []
		if let prop = allProps["isolate"] {
			result.append([prop] as [Any] + [-3, 2, 12, 20, ""])
		}
		if let prop = allProps["group"] {
			result.append([prop] as [Any] + [-20, 16, 68, 93, 94, 96, 99, 101, 105, 111, 115, 117, 120, 126, 129, 134, 136, 141, 143, 147, 149, "Statement", -12, 23, 31, 33, 38, 46, 49, 50, 51, 52, 56, 57, 58, "Type", -18, 12, 17, 18, 19, 20, 21, 22, 66, 67, 69, 70, 71, 72, 73, 74, 77, 81, 86, "Expr"])
		}
		if let prop = allProps["openedBy"] {
			result.append([prop] as [Any] + [13, "(", 25, "{", 53, "["])
		}
		if let prop = allProps["closedBy"] {
			result.append([prop] as [Any] + [26, "}", 14, ")", 54, "]"])
		}
		return result.isEmpty ? nil : result
